 42→export class HevyClient {
 43→  private baseUrl = "https://api.hevyapp.com/v1";
 44→  private apiKey: string;
 45→  private static readonly MAX_PAGES = 50;
 46→
 47→  constructor(apiKey: string) {
 48→    this.apiKey = apiKey;
 49→  }
 50→
 51→  private async request<T>(path: string, init?: RequestInit): Promise<T> {
 52→    const url = `${this.baseUrl}${path}`;
 53→    const res = await fetch(url, {
 54→      ...init,
 55→      headers: {
 56→        "api-key": this.apiKey,
 57→        "accept": "application/json",
 58→        "content-type": "application/json",
 59→        ...(init?.headers ?? {}),
 60→      },
 61→    });
 62→
 63→    if (res.status === 429) {
 64→      throw new Error("RATE_LIMITED");
 65→    }
 66→
 67→    if (!res.ok) {
 68→      const errorBody = await res.text().catch(() => "");
 69→      console.error(`Hevy API ${res.status} ${res.statusText} ${url}: ${errorBody}`);
 70→      throw new Error(`Hevy API error: ${res.status} ${res.statusText}: ${errorBody}`);
 71→    }
 72→
 73→    const text = await res.text();
 74→    try {
 75→      return JSON.parse(text) as T;
 76→    } catch {
 77→      console.error(`Hevy API response not JSON (${url}): ${text.slice(0, 200)}`);
 78→      throw new Error(`Hevy API returned non-JSON: ${text.slice(0, 100)}`);
 79→    }
 80→  }
 81→
 82→  async getExerciseTemplates(page = 1, pageSize = 10): Promise<HevyExerciseTemplate[]> {
 83→    const data = await this.request<{ page: number; page_count: number; exercise_templates: HevyExerciseTemplate[] }>(
 84→      `/exercise_templates?page=${page}&pageSize=${pageSize}`
 85→    );
 86→    return data.exercise_templates;
 87→  }
 88→
 89→  async getAllExerciseTemplates(): Promise<HevyExerciseTemplate[]> {
 90→    const all: HevyExerciseTemplate[] = [];
 91→    let page = 1;
 92→    while (page <= HevyClient.MAX_PAGES) {
 93→      const data = await this.request<{ page: number; page_count: number; exercise_templates: HevyExerciseTemplate[] }>(
 94→        `/exercise_templates?page=${page}&pageSize=100`
 95→      );
 96→      all.push(...data.exercise_templates);
 97→      if (page >= data.page_count) break;
 98→      page++;
 99→    }
100→    return all;
101→  }
102→
103→  async getRoutineFolders(): Promise<{ id: number; title: string }[]> {
104→    const all: { id: number; title: string }[] = [];
105→    let page = 1;
106→    while (page <= HevyClient.MAX_PAGES) {
107→      const data = await this.request<{ page: number; page_count: number; routine_folders: { id: number; title: string }[] }>(
108→        `/routine_folders?page=${page}&pageSize=10`
109→      );
110→      all.push(...data.routine_folders);
111→      if (page >= data.page_count) break;
112→      page++;
113→    }
114→    return all;
115→  }
116→
117→  async createRoutineFolder(name: string): Promise<{ id: number; title: string }> {
118→    const data = await this.request<unknown>("/routine_folders", {
119→      method: "POST",
120→      body: JSON.stringify({ routine_folder: { title: name } }),
121→    });
122→    const obj = data as { routine_folder: { id: number; title: string } };
123→    return obj.routine_folder;
124→  }
125→
126→  async getOrCreateRoutineFolder(name: string): Promise<{ id: number; title: string }> {
127→    const folders = await this.getRoutineFolders();
128→    const existing = folders.find((f) => f.title === name);
129→    if (existing) return existing;
130→    return this.createRoutineFolder(name);
131→  }
132→
133→  async createRoutine(routine: { title: string; folder_id?: number; exercises: HevyRoutineExercise[] }): Promise<HevyRoutine> {
134→    const payload = { routine };
135→    const data = await this.request<unknown>("/routines", {
136→      method: "POST",
137→      body: JSON.stringify(payload),
138→    });
139→    // Hevy returns { routine: [ { id, ... } ] }
140→    const obj = data as Record<string, unknown>;
141→    const routines = obj.routine as HevyRoutine[] | undefined;
142→    if (Array.isArray(routines) && routines.length > 0) return routines[0];
143→    throw new Error(`Unexpected createRoutine response: ${JSON.stringify(data).slice(0, 200)}`);
144→  }
145→
146→  async updateRoutine(routineId: string, routine: { title: string; exercises: HevyRoutineExercise[] }): Promise<HevyRoutine> {
147→    const payload = { routine };
148→    const data = await this.request<{ routine: HevyRoutine }>(`/routines/${routineId}`, {
149→      method: "PUT",
150→      body: JSON.stringify(payload),
151→    });
152→    return data.routine;
153→  }
154→
155→  async createExerciseTemplate(template: {
156→    title: string;
157→    exercise_type: string;
158→    equipment_category: string;
159→    muscle_group: string;
160→    other_muscles: string[];
161→  }): Promise<{ id: string }> {
162→    const url = `${this.baseUrl}/exercise_templates`;
163→    const res = await fetch(url, {
164→      method: "POST",
165→      headers: {
166→        "api-key": this.apiKey,
167→        "accept": "application/json",
168→        "content-type": "application/json",
169→      },
170→      body: JSON.stringify({ exercise: template }),
171→    });
172→
173→    if (!res.ok) {
174→      const errorBody = await res.text().catch(() => "");
175→      console.error(`Hevy API ${res.status} ${res.statusText} ${url}: ${errorBody}`);
176→      throw new Error(`Hevy API error: ${res.status} ${res.statusText}: ${errorBody}`);
177→    }
178→
179→    // Hevy returns just the ID as a plain string
180→    const id = await res.text();
181→    return { id: id.trim() };
182→  }
