104→export default {
105→  async fetch(request: Request, env: Env): Promise<Response> {
106→    try {
107→      const auth = getAuthenticatedUserOrDev(request, env);
108→      const url = new URL(request.url);
109→      const path = url.pathname;
110→      const method = request.method;
111→
112→      // ── GET /programs/default.json ─────────────────────────────
113→      if (method === "GET" && path === "/programs/default.json") {
114→        return new Response(JSON.stringify(defaultProgramJson, null, 2), {
115→          headers: {
116→            "content-type": "application/json",
117→            "content-disposition": 'attachment; filename="default-program.json"',
118→          },
119→        });
120→      }
121→
122→      // ── GET / ──────────────────────────────────────────────────
123→      if (method === "GET" && path === "/") {
124→        const user = await getUser(env.DB, auth.userId);
125→        if (!user) {
126→          return htmlResponse(
127→            htmlShell({
128→              title: APP_NAME,
129→              subtitle: "Setup",
130→              body: `<div id="content">${setupPage()}</div>`,
131→            })
132→          );
133→        }
134→
135→        if (isSSERequest(request)) {
136→          return await handleTodaySSE(env, auth.userId);
137→        }
138→
139→        const subtitle = await loadSubtitle(env.DB, auth.userId);
140→        return htmlResponse(
141→          htmlShell({
142→            title: APP_NAME,
143→            subtitle,
144→            activeTab: "today",
145→            ssePath: "/",
146→          })
147→        );
148→      }
149→
150→      // ── GET /progress ──────────────────────────────────────────
151→      if (method === "GET" && path === "/progress") {
152→        if (isSSERequest(request)) {
153→          return await handleProgressSSE(env, auth.userId);
154→        }
155→
156→        const subtitle = await loadSubtitle(env.DB, auth.userId);
157→        return htmlResponse(
158→          htmlShell({
159→            title: "Progress",
160→            subtitle,
161→            activeTab: "progress",
162→            ssePath: "/progress",
163→          })
164→        );
165→      }
166→
167→      // ── GET /program ──────────────────────────────────────────
168→      if (method === "GET" && path === "/program") {
169→        if (isSSERequest(request)) {
170→          return await handleProgramSSE(env, auth.userId);
171→        }
172→
173→        const subtitle = await loadSubtitle(env.DB, auth.userId);
174→        return htmlResponse(
175→          htmlShell({
176→            title: "Program",
177→            subtitle,
178→            activeTab: "program",
179→            ssePath: "/program",
180→          })
181→        );
182→      }
183→
184→      // ── GET /routine/:id ──────────────────────────────────────
185→      const routineMatch = path.match(/^\/routine\/([^/]+)$/);
186→      if (method === "GET" && routineMatch) {
187→        const routineId = decodeURIComponent(routineMatch[1]);
188→
189→        if (isSSERequest(request)) {
190→          return await handleRoutineSSE(env, auth.userId, routineId);
191→        }
192→
193→        return htmlResponse(
194→          htmlShell({
195→            title: "Routine",
196→            activeTab: "today",
197→            ssePath: `/routine/${encodeURIComponent(routineId)}`,
198→          })
199→        );
200→      }
201→
202→      // ── POST /api/validate-program ─────────────────────────────
203→      if (method === "POST" && path === "/api/validate-program") {
204→        return await handleValidateProgram(request);
205→      }
206→
207→      // ── POST /api/setup/:templateId ─────────────────────────────
208→      const setupMatch = path.match(/^\/api\/setup\/([^/]+)$/);
209→      if (method === "POST" && (path === "/api/setup" || setupMatch)) {
210→        const urlTemplateId = setupMatch ? decodeURIComponent(setupMatch[1]) : undefined;
211→        return await handleSetup(request, env, auth.userId, urlTemplateId);
212→      }
213→
214→      // ── POST /api/push-hevy/:id ────────────────────────────────
215→      const pushMatch = path.match(/^\/api\/push-hevy\/([^/]+)$/);
216→      if (method === "POST" && pushMatch) {
217→        const routineId = decodeURIComponent(pushMatch[1]);
218→        return await handlePush(env, auth.userId, routineId);
219→      }
220→
221→      // ── POST /api/pull ─────────────────────────────────────────
222→      if (method === "POST" && path === "/api/pull") {
223→        return await handlePull(env, auth.userId);
224→      }
225→
226→      // ── POST /api/complete/:id ─────────────────────────────────
227→      const completeMatch = path.match(/^\/api\/complete\/([^/]+)$/);
228→      if (method === "POST" && completeMatch) {
229→        const itemId = parseInt(completeMatch[1], 10);
230→        return await handleManualComplete(env, auth.userId, itemId);
231→      }
232→
233→      // ── 404 ────────────────────────────────────────────────────
234→      return new Response("Not Found", { status: 404 });
235→    } catch (err) {
236→      if (err instanceof Response) return err;
237→      const message = err instanceof Error ? err.message : "Internal Server Error";
238→      const stack = err instanceof Error ? err.stack : "";
239→      console.error("Unhandled error:", message, stack);
240→      return new Response(message, { status: 500 });
241→    }
242→  },
243→};
