296→/** SSE: Today page — CARs card, hero session, completed, upcoming */
297→async function handleTodaySSE(env: Env, userId: string): Promise<Response> {
298→  const user = await getUser(env.DB, userId);
299→  if (!user) {
300→    return sseResponse(
301→      patchElements(setupPage(), { selector: "#content", mode: "inner" })
302→    );
303→  }
304→
305→  const program = await loadProgram(env.DB, userId);
306→  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
307→  const dailyRoutine = program.routines.find((r) => r.isDaily);
308→
309→  const items = await getQueueItems(env.DB, userId);
310→  const today = todayString();
311→
312→  const fragments: string[] = [];
313→
314→  if (dailyRoutine) {
315→    fragments.push(patchElements(carsCard(dailyRoutine), { selector: "#content", mode: "inner" }));
316→  }
317→
318→  // Hero session card — next pending
319→  const nextItem = getNextRoutine(items);
320→  if (nextItem) {
321→    const routine = routineMap.get(nextItem.routine_id);
322→    if (routine) {
323→      fragments.push(
324→        patchElements(heroRoutineCard(routine, nextItem), { selector: "#content", mode: "append" })
325→      );
326→    }
327→  }
328→
329→  // Completed today
330→  const completed = getCompletedRoutines(items, today);
331→  if (completed.length > 0) {
332→    const completedData = completed.map((item) => ({
333→      title: routineMap.get(item.routine_id)?.title ?? item.routine_id,
334→    }));
335→    fragments.push(
336→      patchElements(completedSection(completedData), { selector: "#content", mode: "append" })
337→    );
338→  }
339→
340→  // Upcoming (next 5 sessions)
341→  const template = program.weekTemplates.find((t) => t.id === user.template_id);
342→  if (template) {
343→    const pendingItems = items.filter((i) => i.status === "pending").sort((a, b) => a.position - b.position);
344→    // Skip the first pending (already shown as hero) for upcoming
345→    const upcomingPending = pendingItems.slice(1);
346→    const upcoming = computeUpcoming(upcomingPending, template, program.routines, 5);
347→    if (upcoming.length > 0) {
348→      fragments.push(
349→        patchElements(upcomingSection(upcoming), { selector: "#content", mode: "append" })
350→      );
351→    }
352→  }
353→
354→  return sseResponse(mergeFragments(fragments));
355→}
