```typescript
export function generatePlaylist(
  template: WeekTemplate,
  routines: Routine[],
  weeks: number
): PlaylistItem[] {
  const routineMap = new Map(routines.map((r) => [r.id, r]));
  const mainRoutineOrder: string[] = [];

  for (const day of template.days) {
    if (!day.routineIDs) continue;
    for (const rid of day.routineIDs) {
      const routine = routineMap.get(rid);
      if (routine && !routine.isDaily) {
        mainRoutineOrder.push(rid);
      }
    }
  }

  const playlist: PlaylistItem[] = [];
  for (let week = 0; week < weeks; week++) {
    for (const rid of mainRoutineOrder) {
      playlist.push({
        routine_id: rid,
        position: playlist.length,
      });
    }
  }

  return playlist;
}
```

This function generates queue items with `routine_id` (program routine ID), not Hevy IDs. It does **not** detect duplicates—it simply repeats the template for N weeks. On re-setup, new queue items are generated with the same `program` routine IDs.

