455→/** POST /api/setup — store program, sync Hevy, create user, generate queue */
456→async function handleSetup(request: Request, env: Env, userId: string, urlTemplateId?: string): Promise<Response> {
457→  let body: { apiKey?: string; startDate?: string; templateId?: string; programJson?: string } = {};
458→  try {
459→    body = (await request.json()) as typeof body;
460→  } catch {
461→    // Body may be empty — that's OK, template ID comes from URL
462→  }
463→
464→  const templateId = urlTemplateId ?? body.templateId;
465→  const startDate = body.startDate || todayString();
466→  const apiKey = body.apiKey || undefined;
467→  const programJsonStr = body.programJson;
468→
469→  if (!templateId) {
470→    return new Response("Template ID is required", { status: 400 });
471→  }
472→
473→  if (!programJsonStr) {
474→    return new Response("Program data is required", { status: 400 });
475→  }
476→
477→  // Parse and validate program
478→  let program: Program;
479→  try {
480→    const parsed = JSON.parse(programJsonStr);
481→    const result = validateProgram(parsed);
482→    if (!result.valid) {
483→      return new Response(`Invalid program: ${result.errors.join(", ")}`, { status: 400 });
484→    }
485→    program = result.program;
486→  } catch {
487→    return new Response("Invalid program JSON", { status: 400 });
488→  }
489→
490→  const template = program.weekTemplates.find((t) => t.id === templateId);
491→  if (!template) {
492→    return new Response("Invalid template ID", { status: 400 });
493→  }
494→
495→  // Validate API key against Hevy before proceeding
496→  if (apiKey) {
497→    try {
498→      const client = new HevyClient(apiKey);
499→      await client.getExerciseTemplates(1, 1);
500→    } catch {
501→      return sseResponse(
502→        patchElements(
503→          `<div class="card"><p style="color:var(--orange)">Invalid Hevy API key. Check your key in Hevy Settings &gt; Developer and try again.</p></div>`,
504→          { selector: "#content", mode: "prepend" }
505→        )
506→      );
507→    }
508→  }
509→
510→  // h. Upsert user (must exist before program insert due to FK constraint)
511→  await upsertUser(env.DB, {
512→    id: userId,
513→    active_program: program.meta.title,
514→    template_id: templateId,
515→    start_date: startDate,
516→    hevy_api_key: apiKey,
517→  });
518→
519→  // a. Store program in D1
520→  await insertProgram(env.DB, userId, programJsonStr);
521→
522→  // b-g. Hevy exercise template & routine creation (only with API key)
523→  const routineIdMap = new Map<string, string>();
524→  if (apiKey) {
525→    const client = new HevyClient(apiKey);
526→
527→    // b. Fetch all Hevy exercise templates
528→    const hevyTemplates = await client.getAllExerciseTemplates();
529→
530→    // c. Auto-match our templates to Hevy's by normalized title
531→    const matched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
532→
533→    // d. Create custom Hevy exercise templates for unmatched
534→    const customCreated = new Set<string>();
535→    for (const et of program.exerciseTemplates) {
536→      if (!matched.has(et.id)) {
537→        const enums = mapToHevyEnums(et);
538→        const created = await client.createExerciseTemplate({
539→          title: et.title,
540→          exercise_type: enums.exerciseType,
541→          equipment_category: enums.equipmentCategory,
542→          muscle_group: enums.primaryMuscleGroup,
543→          other_muscles: enums.secondaryMuscleGroups,
544→        });
545→        matched.set(et.id, created.id);
546→        customCreated.add(et.id);
547→      }
548→    }
549→
550→    // e. Save all exercise template mappings
551→    for (const [programTemplateId, hevyTemplateId] of matched) {
552→      await upsertExerciseTemplateMapping(env.DB, {
553→        user_id: userId,
554→        program_template_id: programTemplateId,
555→        hevy_template_id: hevyTemplateId,
556→        is_custom: customCreated.has(programTemplateId) ? 1 : 0,
557→      });
558→    }
559→
560→    // f. Create or update Hevy routines (idempotent — safe to re-run setup)
561→    const allMappings = await getExerciseTemplateMappings(env.DB, userId);
562→    const existingRoutineMappings = await getRoutineMappings(env.DB, userId);
563→    const existingMap = new Map(
564→      existingRoutineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
565→    );
566→
567→    const hasNewRoutines = program.routines.some((r) => !existingMap.has(r.id));
568→    const folder = hasNewRoutines
569→      ? await client.getOrCreateRoutineFolder(program.meta.title)
570→      : null;
571→
572→    for (const routine of program.routines) {
573→      const payload = buildRoutinePayload(routine, allMappings);
574→      const existingHevyId = existingMap.get(routine.id);
575→
576→      if (existingHevyId) {
577→        await client.updateRoutine(existingHevyId, {
578→          title: payload.title,
579→          exercises: payload.exercises,
580→        });
581→        routineIdMap.set(routine.id, existingHevyId);
582→      } else {
583→        if (!folder) throw new Error(`No folder created but routine "${routine.id}" needs one`);
584→        const created = await client.createRoutine({
585→          title: payload.title,
586→          folder_id: folder.id,
587→          exercises: payload.exercises,
588→        });
589→        routineIdMap.set(routine.id, created.id);
590→      }
591→    }
592→
593→    // g. Save all routine mappings
594→    for (const [programRoutineId, hevyRoutineId] of routineIdMap) {
595→      await upsertRoutineMapping(env.DB, {
596→        user_id: userId,
597→        program_routine_id: programRoutineId,
598→        hevy_routine_id: hevyRoutineId,
599→      });
600→    }
601→  }
602→
603→  // i. Generate queue playlist
604→  const weeks = program.meta.durationWeeks || 8;
605→  const playlist = generatePlaylist(template, program.routines, weeks);
606→  if (playlist.length > 0) {
607→    await insertQueueItems(env.DB, userId, playlist);
608→  }
609→
610→  // j. Bulk-set hevy_routine_id on queue items via routine_mappings
611→  if (apiKey) {
612→    await bulkSetQueueItemRoutineIds(env.DB, userId, routineIdMap);
613→  }
614→
615→  // k. Redirect to Today
616→  return sseResponse(executeScript("window.location.href = '/'"));
617→}
