619→/** POST /api/push-hevy/:id — open routine in Hevy (uses existing mapping from setup) */
620→async function handlePush(env: Env, userId: string, routineId: string): Promise<Response> {
621→  const user = await getUser(env.DB, userId);
622→  if (!user || !user.hevy_api_key) {
623→    return sseResponse(
624→      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
625→        selector: "#content",
626→        mode: "inner",
627→      })
628→    );
629→  }
630→
631→  // Look up existing routine mapping from setup
632→  const routineMappings = await getRoutineMappings(env.DB, userId);
633→  const mapping = routineMappings.find((m) => m.program_routine_id === routineId);
634→
635→  if (mapping) {
636→    // Routine already exists in Hevy — just link to it
637→    return sseResponse(
638→      patchElements(
639→        `<div class="card"><p style="color:var(--green)">Ready in Hevy! Open the Hevy app and start the routine.</p></div>`,
640→        { selector: "#content", mode: "prepend" }
641→      )
642→    );
643→  }
644→
645→  // Fallback: no mapping exists (edge case — setup didn't create this routine)
646→  const program = await loadProgram(env.DB, userId);
647→  const routine = program.routines.find((r) => r.id === routineId);
648→  if (!routine) {
649→    return new Response("Routine not found", { status: 404 });
650→  }
651→
652→  const client = new HevyClient(user.hevy_api_key);
653→
654→  // Get or auto-create exercise template mappings
655→  let mappings = await getExerciseTemplateMappings(env.DB, userId);
656→  if (mappings.length === 0) {
657→    try {
658→      const hevyTemplates = await client.getAllExerciseTemplates();
659→      const autoMatched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
660→
661→      for (const [programTemplateId, hevyTemplateId] of autoMatched) {
662→        await upsertExerciseTemplateMapping(env.DB, {
663→          user_id: userId,
664→          program_template_id: programTemplateId,
665→          hevy_template_id: hevyTemplateId,
666→          is_custom: 0,
667→        });
668→      }
669→      mappings = await getExerciseTemplateMappings(env.DB, userId);
670→    } catch {
671→      // If auto-match fails, continue with empty mappings
672→    }
673→  }
674→
675→  const payload = buildRoutinePayload(routine, mappings);
676→
677→  if (payload.exercises.length === 0) {
678→    return sseResponse(
679→      patchElements(
680→        `<div class="card"><p style="color:var(--orange)">Cannot push: no exercises could be mapped to Hevy templates. ${payload.unmapped.length} unmapped exercise(s).</p></div>`,
681→        { selector: "#content", mode: "prepend" }
682→      )
683→    );
684→  }
685→
686→  try {
687→    const folder = await client.getOrCreateRoutineFolder(program.meta.title);
688→    const created = await client.createRoutine({
689→      title: payload.title,
690→      folder_id: folder.id,
691→      exercises: payload.exercises,
692→    });
693→
694→    // Save the mapping so future pushes use the existing routine
695→    await upsertRoutineMapping(env.DB, {
696→      user_id: userId,
697→      program_routine_id: routineId,
698→      hevy_routine_id: created.id,
699→    });
700→
701→    // Also update the queue item if there is one
702→    const items = await getQueueItems(env.DB, userId);
703→    const queueItem = items.find(
704→      (i) => i.routine_id === routineId && i.status === "pending"
705→    );
706→    if (queueItem) {
707→      await updateQueueItemHevyRoutineId(env.DB, queueItem.id, created.id);
708→    }
709→
710→    return sseResponse(
711→      patchElements(
712→        `<div class="card"><p style="color:var(--green)">Created routine in Hevy. Open the Hevy app to start it.</p></div>`,
713→        { selector: "#content", mode: "prepend" }
714→      )
715→    );
716→  } catch (err) {
717→    const msg = escapeHtml(err instanceof Error ? err.message : "Push failed");
718→    return sseResponse(
719→      patchElements(
720→        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
721→        { selector: "#content", mode: "prepend" }
722→      )
723→    );
724→  }
725→}
