727→/** POST /api/pull — pull completions from Hevy */
728→async function handlePull(env: Env, userId: string): Promise<Response> {
729→  const user = await getUser(env.DB, userId);
730→  if (!user || !user.hevy_api_key) {
731→    return sseResponse(
732→      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
733→        selector: "#content",
734→        mode: "inner",
735→      })
736→    );
737→  }
738→
739→  const program = await loadProgram(env.DB, userId);
740→  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
741→  const client = new HevyClient(user.hevy_api_key);
742→
743→  try {
744→    const [workouts, items] = await Promise.all([
745→      client.getRecentWorkouts(),
746→      getQueueItems(env.DB, userId),
747→    ]);
748→    const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);
749→
750→    const nameToRoutineId = new Map<string, string>();
751→    for (const item of pendingItems) {
752→      const routine = routineMap.get(item.routine_id);
753→      if (routine && item.hevy_routine_id) {
754→        nameToRoutineId.set(routine.title, item.hevy_routine_id);
755→      }
756→    }
757→
758→    const matches = matchCompletions(
759→      pendingItems,
760→      workouts,
761→      (w) => nameToRoutineId.get(w.name) ?? null
762→    );
763→
764→    const today = todayString();
765→    for (const match of matches) {
766→      await markQueueItemCompleted(env.DB, match.queueItemId, today, match.workoutId);
767→    }
768→
769→    // Re-render today page
770→    return await handleTodaySSE(env, userId);
771→  } catch (err) {
772→    const msg = escapeHtml(err instanceof Error ? err.message : "Pull failed");
773→    return sseResponse(
774→      patchElements(
775→        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
776→        { selector: "#content", mode: "prepend" }
777→      )
778→    );
779→  }
780→}
