107→/**
108→ * Build a Hevy exercise template creation payload from a domain ExerciseTemplate.
109→ * Pure mapping from domain shape (camelCase) to wire shape (snake_case).
110→ */
111→export function buildExerciseTemplatePayload(
112→  template: ExerciseTemplate
113→): ExerciseTemplatePayload {
114→  return {
115→    title: template.title,
116→    exercise_type: template.type,
117→    equipment_category: template.equipmentCategory,
118→    primary_muscle_group: template.primaryMuscleGroup,
119→    other_muscles: template.secondaryMuscleGroups ?? [],
120→  };
121→}
