123→// ──────────────────────────────────────────────────────────────────
124→// matchCompletions
125→// ──────────────────────────────────────────────────────────────────
126→
127→export interface CompletionMatch {
128→  queueItemId: number;
129→  workoutId: string;
130→}
131→
132→/**
133→ * Match Hevy workouts to queue items by comparing each workout's routine ID
134→ * (obtained via `getRoutineId`) to the `hevy_routine_id` stored on the queue
135→ * item.
136→ *
137→ * Each workout is matched to at most one queue item.
138→ */
139→export function matchCompletions(
140→  items: Pick<QueueItemRow, "id" | "hevy_routine_id">[],
141→  workouts: HevyWorkout[],
142→  getRoutineId: (workout: HevyWorkout) => string | null
143→): CompletionMatch[] {
144→  // Build a map: routine_id → queue item id
145→  const routineToItem = new Map<string, number>();
146→  for (const item of items) {
147→    if (item.hevy_routine_id) {
148→      routineToItem.set(item.hevy_routine_id, item.id);
149→    }
150→  }
151→
152→  const matches: CompletionMatch[] = [];
153→  const usedItems = new Set<number>();
154→
155→  for (const workout of workouts) {
156→    const routineId = getRoutineId(workout);
157→    if (!routineId) continue;
158→
159→    const itemId = routineToItem.get(routineId);
160→    if (itemId !== undefined && !usedItems.has(itemId)) {
161→      matches.push({ queueItemId: itemId, workoutId: workout.id });
162→      usedItems.add(itemId);
163→    }
164→  }
165→
166→  return matches;
167→}
168→
169→// ──────────────────────────────────────────────────────────────────
170→// autoMatchExercises
171→// ──────────────────────────────────────────────────────────────────
172→
173→/**
174→ * Normalize an exercise name for fuzzy matching:
175→ * - Lowercase
176→ * - Strip non-alphanumeric characters (spaces, hyphens, punctuation)
177→ * - Strip a trailing 's' (basic singular/plural normalisation)
178→ */
179→function normalizeName(name: string): string {
180→  return name
181→    .toLowerCase()
182→    .replace(/[^a-z0-9]/g, "")
183→    .replace(/s$/, "");
184→}
185→
186→/**
187→ * Attempt to automatically match our exercise templates to Hevy exercise
188→ * template IDs using normalized title comparison. Supports partial matching
189→ * (one normalized name contains the other).
190→ *
191→ * Returns a Map of our template ID → Hevy template ID for every template
192→ * that could be matched.
193→ */
194→export function autoMatchExercises(
195→  ourTemplates: ExerciseTemplate[],
196→  hevyTemplates: HevyExerciseTemplate[]
197→): Map<string, string> {
198→  const result = new Map<string, string>();
199→
200→  // Pre-normalize Hevy template titles
201→  const normalizedHevy = hevyTemplates.map((t) => ({
202→    id: t.id,
203→    norm: normalizeName(t.title),
204→  }));
205→
206→  for (const template of ourTemplates) {
207→    const normOurs = normalizeName(template.title);
208→
209→    // Prefer exact match first
210→    let matched = normalizedHevy.find((t) => t.norm === normOurs);
211→
212→    // Fall back to partial match (one contains the other)
213→    if (!matched) {
214→      matched = normalizedHevy.find(
215→        (t) => t.norm.includes(normOurs) || normOurs.includes(t.norm)
216→      );
217→    }
218→
219→    if (matched) {
220→      result.set(template.id, matched.id);
221→    }
222→  }
223→
224→  return result;
225→}
