export function reconcileRoutines(
  assignments: RoutineFolderAssignment[],
  existingHevyRoutines: Array<{ id: string; title: string; folderId?: number }>,
  folderNameToId: Map<string, number>,
  existingMappings: Map<string, string>  // program_routine_id -> hevy_routine_id
): RoutineReconciliation[] {
