    }
    // Then check Hevy by title + folder
    const targetFolderId = folderNameToId.get(a.folderName);
    const match = existingHevyRoutines.find(
      (r) => r.title === a.routineTitle && r.folderId === targetFolderId
    );
    if (match) {
      return { programRoutineId: a.routineId, action: "update", existingHevyRoutineId: match.id, folderName: a.folderName };
    }
    return { programRoutineId: a.routineId, action: "create", folderName: a.folderName };
  });
}
