async function handleCleanupRoutines(env: Env, userId: string): Promise<Response> {
  const user = await getUser(env.DB, userId);
  if (!user || !user.hevy_api_key) {
    return sseResponse(patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, { selector: "#content", mode: "prepend" }));
  }

  const program = await loadProgram(env.DB, userId);
  const client = new HevyClient(user.hevy_api_key);
  const allHevyRoutines = await client.getAllRoutines();

  // Build set of known routine titles from program
  const knownTitles = new Set(program.routines.map(r => r.title));

  // Find duplicates: routines with same title in same folder
  const byTitleAndFolder = new Map<string, typeof allHevyRoutines>();
  for (const r of allHevyRoutines) {
    const key = `${r.title}::${r.folderId}`;
    const list = byTitleAndFolder.get(key) ?? [];
    list.push(r);
    byTitleAndFolder.set(key, list);
  }

  const toDelete: string[] = [];
  for (const [, routines] of byTitleAndFolder) {
    if (routines.length > 1) {
      // Keep the most recently updated, delete the rest
      routines.sort((a, b) => /* by updatedAt desc */);
      toDelete.push(...routines.slice(1).map(r => r.id));
    }
  }

  let deleted = 0;
  let failed = 0;
  for (const id of toDelete) {
    try {
      await client.deleteRoutine(id);
      deleted++;
    } catch {
      failed++;
    }
  }

  return sseResponse(
    patchElements(
      `<div class="card"><p style="color:var(--green)">Cleanup complete: ${deleted} duplicate(s) removed, ${failed} failed.</p></div>`,
      { selector: "#content", mode: "prepend" }
    )
  );
}
