{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://github.com/ryanriley/mobility-tracker/schema/program.schema.json",
  "title": "Training Program",
  "description": "Schema for defining a training program. Programs contain exercise templates, routines, weekly schedule templates, progression phases, optional skill goals, benchmarks, and a long-term roadmap.",
  "type": "object",
  "required": ["meta", "exerciseTemplates", "routines", "weekTemplates", "progressions"],
  "additionalProperties": false,
  "properties": {

    "meta": {
      "type": "object",
      "description": "Program metadata.",
      "required": ["version", "title"],
      "additionalProperties": false,
      "properties": {
        "version": {
          "type": "string",
          "description": "Schema version (semver).",
          "pattern": "^\\d+\\.\\d+\\.\\d+$"
        },
        "title": {
          "type": "string",
          "description": "Program title displayed in the app."
        },
        "subtitle": {
          "type": "string"
        },
        "description": {
          "type": "string",
          "description": "Brief description of the program's purpose and scope."
        },
        "author": {
          "type": "string"
        },
        "durationWeeks": {
          "type": "integer",
          "minimum": 0,
          "description": "Total program duration in weeks. 0 = ongoing/indefinite."
        },
        "tags": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Searchable tags (e.g., 'mobility', 'strength', 'calisthenics')."
        }
      }
    },

    "exerciseTemplates": {
      "type": "array",
      "description": "All exercise templates in the program. Each template defines an exercise's identity, category, and optional per-phase progression.",
      "items": { "$ref": "#/$defs/exerciseTemplate" },
      "minItems": 1
    },

    "routines": {
      "type": "array",
      "description": "All routines in the program. A routine is a named group of exercise references done together.",
      "items": { "$ref": "#/$defs/routine" },
      "minItems": 1
    },

    "weekTemplates": {
      "type": "array",
      "description": "Weekly schedule templates. Users select one template to follow.",
      "items": { "$ref": "#/$defs/weekTemplate" },
      "minItems": 1
    },

    "progressions": {
      "type": "array",
      "description": "Progression phases within the program (e.g., Foundation, Build, Load). Coaching notes adjust per phase.",
      "items": { "$ref": "#/$defs/progression" }
    },

    "roadmap": {
      "type": "array",
      "description": "Optional long-term roadmap phases beyond the core program (e.g., Skill Acquisition, Refinement). Each phase may span many weeks and gate on benchmarks.",
      "items": { "$ref": "#/$defs/roadmapPhase" }
    },

    "skills": {
      "type": "array",
      "description": "Optional long-term skill goals tracked across the roadmap (e.g., Muscle Up, Pistol Squat).",
      "items": { "$ref": "#/$defs/skill" }
    },

    "benchmarks": {
      "type": "array",
      "description": "Optional measurable assessments for tracking progress. Can serve as gate tests between roadmap phases.",
      "items": { "$ref": "#/$defs/benchmark" }
    },

    "foundations": {
      "type": "array",
      "description": "Optional foundational protocols (breathing, bracing, warmup rituals) that apply across the program.",
      "items": { "$ref": "#/$defs/foundation" }
    },

    "resources": {
      "type": "array",
      "description": "Optional reference materials, links, and educational resources.",
      "items": { "$ref": "#/$defs/resource" }
    },

    "bodi": {
      "type": "array",
      "description": "Optional BODi integration notes for combining with BODi workouts.",
      "items": { "$ref": "#/$defs/bodiIntegration" }
    },

    "theme": {
      "$ref": "#/$defs/theme",
      "description": "Optional color theme for the program."
    }
  },

  "$defs": {

    "exerciseTemplate": {
      "type": "object",
      "required": ["id", "title", "type", "equipmentCategory", "primaryMuscleGroup"],
      "additionalProperties": false,
      "properties": {
        "id": {
          "type": "string",
          "description": "Unique identifier for the exercise template within this program."
        },
        "title": { "type": "string" },
        "type": {
          "type": "string",
          "enum": ["duration", "reps_only", "bodyweight_reps", "weight_reps", "weight_duration"],
          "description": "Exercise type controlling which fields are logged per set."
        },
        "equipmentCategory": {
          "type": "string",
          "enum": [
            "barbell", "dumbbell", "machine", "cable", "bodyweight",
            "band", "kettlebell", "other", "weighted_bodyweight",
            "assisted_bodyweight", "cardio", "duration", "resistance_band", "none",
            "foam_roller", "pull_up_bar"
          ],
          "description": "Equipment required. Hevy-native values sync directly; program-specific values (foam_roller, pull_up_bar) are mapped to 'other' at sync time."
        },
        "primaryMuscleGroup": {
          "type": "string",
          "enum": [
            "abdominals", "abductors", "adductors", "biceps", "calves",
            "cardio", "chest", "forearms", "full_body", "glutes",
            "hamstrings", "lats", "lower_back", "neck", "other",
            "quadriceps", "shoulders", "triceps", "traps", "upper_back",
            "hip_flexors", "obliques"
          ],
          "description": "Primary muscle group targeted. Hevy-native values sync directly; program-specific values (hip_flexors, obliques) are mapped at sync time."
        },
        "secondaryMuscleGroups": {
          "type": "array",
          "items": {
            "type": "string",
            "enum": [
              "abdominals", "abductors", "adductors", "biceps", "calves",
              "cardio", "chest", "forearms", "full_body", "glutes",
              "hamstrings", "lats", "lower_back", "neck", "other",
              "quadriceps", "shoulders", "triceps", "traps", "upper_back",
              "hip_flexors", "obliques"
            ]
          },
          "description": "Additional muscle groups involved."
        },
        "notes": {
          "type": "string",
          "description": "Coaching notes, cues, and technique guidance."
        },
        "videoURL": {
          "type": ["string", "null"],
          "format": "uri",
          "description": "Link to a tutorial video."
        },
        "searchTerms": {
          "type": ["string", "null"],
          "description": "Search keywords for finding tutorial videos."
        },
        "tags": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Tags indicating cross-cutting concerns (e.g., 'core-integration', 'tspine-integration', 'glute-activation')."
        },
        "progressionByPhase": {
          "type": "object",
          "description": "Optional per-phase overrides for sets or notes. Keys are progression phase names.",
          "additionalProperties": {
            "type": "object",
            "properties": {
              "sets": { "type": "string" },
              "notes": { "type": "string" }
            }
          }
        }
      }
    },

    "routine": {
      "type": "object",
      "required": ["id", "title", "exercises"],
      "additionalProperties": false,
      "properties": {
        "id": {
          "type": "string",
          "description": "Unique identifier for the routine within this program."
        },
        "title": { "type": "string" },
        "subtitle": { "type": "string" },
        "description": {
          "type": "string",
          "description": "Coaching context explaining why this routine exists and what it targets."
        },
        "color": {
          "type": "string",
          "description": "Optional CSS color string for theming this routine (e.g., 'rgb(96, 165, 224)')."
        },
        "isDaily": {
          "type": "boolean",
          "description": "If true, this routine resets daily (never reflowed when missed, just dropped and regenerated)."
        },
        "sortOrder": {
          "type": "integer",
          "description": "Display order in the program view."
        },
        "exercises": {
          "type": "array",
          "items": { "$ref": "#/$defs/routineExercise" },
          "minItems": 1
        }
      }
    },

    "routineExercise": {
      "type": "object",
      "required": ["exerciseTemplateId", "sets"],
      "additionalProperties": false,
      "properties": {
        "exerciseTemplateId": {
          "type": "string",
          "description": "Reference to an exerciseTemplate id defined in this program."
        },
        "sets": {
          "type": "string",
          "description": "Human-readable set/rep scheme (e.g., '3×8 each side', '2×45 sec')."
        },
        "notes": {
          "type": "string",
          "description": "Routine-specific coaching notes or cues for this exercise slot."
        }
      }
    },

    "weekTemplate": {
      "type": "object",
      "required": ["id", "name", "days"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "name": {
          "type": "string",
          "description": "Display name (e.g., '5-Day (Recommended)')."
        },
        "description": { "type": "string" },
        "sortOrder": { "type": "integer" },
        "days": {
          "type": "array",
          "description": "Seven entries, one per day of the week (Monday=index 0).",
          "items": { "$ref": "#/$defs/daySlot" },
          "minItems": 7,
          "maxItems": 7
        }
      }
    },

    "daySlot": {
      "type": "object",
      "required": ["dayOfWeek"],
      "additionalProperties": false,
      "properties": {
        "dayOfWeek": {
          "type": "integer",
          "minimum": 0,
          "maximum": 6,
          "description": "0=Monday, 6=Sunday."
        },
        "routineIDs": {
          "type": "array",
          "items": { "type": "string" },
          "default": [],
          "description": "References to routine IDs scheduled for this day. Empty = rest or user-directed."
        },
        "note": {
          "type": ["string", "null"],
          "description": "Optional coaching note for the day (e.g., 'Strength training — CARs as warmup')."
        }
      }
    },

    "progression": {
      "type": "object",
      "required": ["id", "weekRange", "phaseName"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "weekRange": {
          "type": "string",
          "description": "Human-readable week range (e.g., 'Weeks 1-2')."
        },
        "phaseName": {
          "type": "string",
          "description": "Phase name (e.g., 'Foundation', 'Build', 'Load')."
        },
        "focus": {
          "type": "string",
          "description": "One-line coaching summary for this phase."
        },
        "details": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Specific coaching adjustments and guidance for this phase."
        },
        "weekStart": {
          "type": "integer",
          "minimum": 1,
          "description": "First week number of this phase (for programmatic use)."
        },
        "weekEnd": {
          "type": "integer",
          "minimum": 1,
          "description": "Last week number of this phase."
        },
        "sortOrder": { "type": "integer" }
      }
    },

    "roadmapPhase": {
      "type": "object",
      "required": ["id", "name"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "name": {
          "type": "string",
          "description": "Phase name (e.g., 'Phase 2: Strength Prerequisites')."
        },
        "weeks": {
          "type": "string",
          "description": "Human-readable duration (e.g., 'Weeks 9-20')."
        },
        "status": {
          "type": "string",
          "enum": ["current", "future", "completed"],
          "default": "future"
        },
        "summary": { "type": "string" },
        "keyFocus": {
          "type": "string",
          "description": "Coaching guidance for this roadmap phase."
        },
        "gateTests": {
          "type": "array",
          "items": { "type": "string" },
          "description": "References to benchmark IDs that must pass before advancing to the next phase."
        },
        "color": { "type": "string" },
        "sortOrder": { "type": "integer" }
      }
    },

    "skill": {
      "type": "object",
      "required": ["id", "name"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "name": {
          "type": "string",
          "description": "Skill name (e.g., 'Muscle Up')."
        },
        "priority": {
          "type": "integer",
          "minimum": 1,
          "description": "Priority ranking (1 = highest)."
        },
        "icon": { "type": "string" },
        "color": { "type": "string" },
        "currentState": {
          "type": "string",
          "description": "Starting assessment of the user's ability."
        },
        "requirements": {
          "type": "string",
          "description": "What's needed to achieve this skill."
        },
        "gapAnalysis": {
          "type": "string",
          "description": "What's missing and how the program addresses it."
        },
        "timeline": {
          "type": "string",
          "description": "Expected progression milestones with timeframes."
        },
        "milestones": {
          "type": "array",
          "description": "Ordered list of sub-goals on the way to the skill.",
          "items": {
            "type": "object",
            "required": ["name"],
            "additionalProperties": false,
            "properties": {
              "name": { "type": "string" },
              "description": { "type": "string" },
              "targetWeek": {
                "type": "integer",
                "description": "Approximate week number when this milestone might be reached."
              }
            }
          }
        }
      }
    },

    "benchmark": {
      "type": "object",
      "required": ["id", "name", "howTo"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "name": {
          "type": "string",
          "description": "Benchmark name (e.g., 'Wall Dorsiflexion Test')."
        },
        "howTo": {
          "type": "string",
          "description": "Instructions for performing the assessment."
        },
        "target": {
          "type": "string",
          "description": "What a passing result looks like."
        },
        "frequency": {
          "type": "string",
          "description": "How often to retest (e.g., 'Every 2 weeks')."
        },
        "unit": {
          "type": "string",
          "description": "Optional measurement unit (e.g., 'inches', 'seconds')."
        }
      }
    },

    "foundation": {
      "type": "object",
      "required": ["id", "title"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "title": {
          "type": "string",
          "description": "Protocol name (e.g., 'Breathing & Bracing Protocol')."
        },
        "description": { "type": "string" },
        "steps": {
          "type": "array",
          "items": {
            "type": "object",
            "required": ["name", "instructions"],
            "additionalProperties": false,
            "properties": {
              "step": { "type": "integer" },
              "name": { "type": "string" },
              "instructions": { "type": "string" },
              "videoSearch": { "type": "string" }
            }
          }
        },
        "practice": {
          "type": "string",
          "description": "How and when to practice this protocol (e.g., '10 breaths before daily CARs for the first 2 weeks')."
        },
        "activeDuringWeeks": {
          "type": "object",
          "description": "Optional week range when this foundation is actively cued.",
          "properties": {
            "start": { "type": "integer" },
            "end": { "type": "integer" }
          }
        }
      }
    },

    "resource": {
      "type": "object",
      "required": ["id", "title"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "title": { "type": "string" },
        "url": { "type": "string", "format": "uri" },
        "description": { "type": "string" },
        "category": { "type": "string" }
      }
    },

    "bodiIntegration": {
      "type": "object",
      "required": ["id", "title"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string" },
        "title": { "type": "string" },
        "description": { "type": "string" },
        "schedule": { "type": "string" },
        "notes": { "type": "string" }
      }
    },

    "theme": {
      "type": "object",
      "description": "Optional visual theme for the program.",
      "additionalProperties": false,
      "properties": {
        "backgroundColor": { "type": "string" },
        "textColor": { "type": "string" },
        "accentColor": { "type": "string" },
        "routineColors": {
          "type": "object",
          "description": "Per-routine color overrides. Keys are routine IDs.",
          "additionalProperties": {
            "type": "object",
            "properties": {
              "background": { "type": "string" },
              "accent": { "type": "string" }
            }
          }
        }
      }
    }
  }
}

