// ──────────────────────────────────────────────────────────────────
// Worker entry point — router with content negotiation
// ──────────────────────────────────────────────────────────────────

import { getAuthenticatedUserOrDev } from "./auth/access";
import {
  executeScript,
  isSSERequest,
