import type { Routine, ExerciseTemplate, ExerciseTemplateMappingRow, QueueItemRow } from "../types";
import type { HevyRoutineExercise, HevySet, HevyWorkout, HevyExerciseTemplate } from "../hevy/client";

// ──────────────────────────────────────────────────────────────────
// Sets string parser
// ──────────────────────────────────────────────────────────────────

/**
 * Parse a sets string like "3×8", "3×30 sec", "2×45 sec", "3×1 min"
 * into an array of HevySet objects.
 *
 * - Patterns containing "sec" or "min" produce duration_seconds sets.
 * - All other patterns produce reps sets.
 */
function parseSetsString(setsStr: string): HevySet[] {
  // Normalise the multiplication sign — programs may use × (U+00D7) or x
  const normalised = setsStr.replace(/×/g, "x");

  // Match "NxM sec", "NxM min", or "NxM"
  const match = normalised.match(/^(\d+)\s*x\s*(\d+(?:\.\d+)?)\s*(sec|min)?/i);
  if (!match) {
    // Fallback: return a single normal set with no values
    return [{ type: "normal", reps: null }];
  }

  const count = parseInt(match[1], 10);
  const value = parseFloat(match[2]);
  const unit = match[3]?.toLowerCase();

  const isDuration = unit === "sec" || unit === "min";
  const duration_seconds = isDuration
    ? unit === "min"
      ? Math.round(value * 60)
      : Math.round(value)
    : undefined;

  const sets: HevySet[] = [];
  for (let i = 0; i < count; i++) {
    if (isDuration) {
      sets.push({ type: "normal", reps: null, duration_seconds });
    } else {
      const reps = Math.round(value);
      sets.push({ type: "normal", reps });
    }
  }
  return sets;
}

// ──────────────────────────────────────────────────────────────────
// buildRoutinePayload
// ──────────────────────────────────────────────────────────────────

export interface RoutinePayload {
  title: string;
  exercises: HevyRoutineExercise[];
  /** Exercise template IDs from the routine that had no mapping */
  unmapped: string[];
}

/**
 * Build a Hevy routine payload from a program routine + exercise template mappings.
 * Exercises without a mapping are collected in `unmapped` and omitted from
 * the payload.
 */
export function buildRoutinePayload(
  routine: Routine,
  mappings: ExerciseTemplateMappingRow[]
): RoutinePayload {
  const mappingMap = new Map(
    mappings.map((m) => [m.program_template_id, m.hevy_template_id])
  );

  const exercises: HevyRoutineExercise[] = [];
  const unmapped: string[] = [];

  for (const exercise of routine.exercises) {
    const hevyId = mappingMap.get(exercise.exerciseTemplateId);
    if (!hevyId) {
      unmapped.push(exercise.exerciseTemplateId);
      continue;
    }

    const sets = parseSetsString(exercise.sets);

    exercises.push({
      exercise_template_id: hevyId,
      sets,
      notes: exercise.notes,
    });
  }

  return { title: routine.title, exercises, unmapped };
}

// ──────────────────────────────────────────────────────────────────
// Folder assignments & reconciliation
// ──────────────────────────────────────────────────────────────────

export interface RoutineFolderAssignment {
  routineId: string;
  routineTitle: string;
  folderName: string;
}

/**
 * Compute which Hevy folder each routine should belong to.
 * Uses routine.folderGroup if set, falls back to "Daily" for isDaily,
 * or programTitle for everything else.
 */
export function computeFolderAssignments(
  routines: Routine[],
  programTitle: string
): RoutineFolderAssignment[] {
  return routines.map((r) => ({
    routineId: r.id,
    routineTitle: r.title,
    folderName: r.folderGroup ?? (r.isDaily ? "Daily" : programTitle),
  }));
}

export interface RoutineReconciliation {
  programRoutineId: string;
  action: "create" | "update";
  existingHevyRoutineId?: string;
  folderName: string;
}

/**
 * Reconcile program routines against existing Hevy routines.
 * Checks D1 mappings first, then matches by title within the target folder.
 */
export function reconcileRoutines(
  assignments: RoutineFolderAssignment[],
  existingHevyRoutines: Array<{ id: string; title: string; folderId?: number }>,
  folderNameToId: Map<string, number>,
  existingMappings: Map<string, string>
): RoutineReconciliation[] {
  return assignments.map((a) => {
    // First check existing D1 mapping
    const mappedId = existingMappings.get(a.routineId);
    if (mappedId) {
      return { programRoutineId: a.routineId, action: "update" as const, existingHevyRoutineId: mappedId, folderName: a.folderName };
    }
    // Then check Hevy by title + folder
    const targetFolderId = folderNameToId.get(a.folderName);
    if (targetFolderId !== undefined) {
      const match = existingHevyRoutines.find(
        (r) => r.title === a.routineTitle && r.folderId === targetFolderId
      );
      if (match) {
        return { programRoutineId: a.routineId, action: "update" as const, existingHevyRoutineId: match.id, folderName: a.folderName };
      }
    }
    return { programRoutineId: a.routineId, action: "create" as const, folderName: a.folderName };
  });
}

// ──────────────────────────────────────────────────────────────────
// buildExerciseTemplatePayload
